package main

import (
	"fmt"
	"os/exec"
	"path/filepath"
	"strings"
)

// QuerySLBAndExport executes the aliyun CLI command to describe SLB,
// processes the output with jq, and saves it to the specified file.
// Returns the stdout of the command pipeline and any error encountered.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Validate input parameters
	if err := validateInput(loadBalancerName, outputFile); err != nil {
		return "", err
	}

	// Use separate commands without shell injection vulnerability
	// First command: aliyun slb DescribeLoadBalancers
	cmd1 := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)

	// Second command: jq to filter the output
	cmd2 := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	// Pipe cmd1 output to cmd2
	cmd2.Stdin, _ = cmd1.StdoutPipe()

	// Start both commands
	if err := cmd1.Start(); err != nil {
		return "", fmt.Errorf("failed to start aliyun command: %w", err)
	}

	// Capture output from jq
	outputBytes, err := cmd2.CombinedOutput()
	outputStr := string(outputBytes)

	// Wait for first command to finish
	if err1 := cmd1.Wait(); err1 != nil {
		return outputStr, fmt.Errorf("aliyun command failed: %w", err1)
	}

	// Check if jq command failed
	if err != nil {
		return outputStr, fmt.Errorf("jq command failed: %w, output: %s", err, outputStr)
	}

	// Write output to file
	if err := writeToFile(outputFile, outputStr); err != nil {
		return outputStr, fmt.Errorf("failed to write to file: %w", err)
	}

	return outputStr, nil
}

// validateInput performs comprehensive validation on input parameters
func validateInput(loadBalancerName string, outputFile string) error {
	// Check for empty inputs
	if strings.TrimSpace(loadBalancerName) == "" {
		return fmt.Errorf("loadBalancerName cannot be empty")
	}

	if strings.TrimSpace(outputFile) == "" {
		return fmt.Errorf("outputFile cannot be empty")
	}

	// Check length limits to prevent DoS
	if len(loadBalancerName) > 255 {
		return fmt.Errorf("loadBalancerName exceeds maximum length")
	}

	if len(outputFile) > 4096 {
		return fmt.Errorf("outputFile path exceeds maximum length")
	}

	// Validate output file path to prevent directory traversal
	absPath, err := filepath.Abs(outputFile)
	if err != nil {
		return fmt.Errorf("invalid output file path: %w", err)
	}

	// Ensure the path doesn't contain suspicious patterns
	if strings.Contains(absPath, "..") {
		return fmt.Errorf("output file path contains directory traversal patterns")
	}

	// Validate characters in loadBalancerName (allow alphanumeric, hyphens, underscores)
	for _, ch := range loadBalancerName {
		if !isValidNameChar(ch) {
			return fmt.Errorf("loadBalancerName contains invalid characters")
		}
	}

	return nil
}

// isValidNameChar checks if a character is valid for load balancer names
func isValidNameChar(ch rune) bool {
	return (ch >= 'a' && ch <= 'z') ||
		(ch >= 'A' && ch <= 'Z') ||
		(ch >= '0' && ch <= '9') ||
		ch == '-' || ch == '_'
}

// writeToFile safely writes content to a file
func writeToFile(filePath string, content string) error {
	// Use os.WriteFile for atomic write operations
	return os.WriteFile(filePath, []byte(content), 0644)
}

func main() {
	// Example usage
	result, err := QuerySLBAndExport("my-slb", "/tmp/output.json")
	if err != nil {
		fmt.Printf("Error: %v\n", err)
		return
	}
	fmt.Printf("Success: %s\n", result)
}

