package main

import (
	"fmt"
	"os"
	"os/exec"
)

// QuerySLBAndExport queries SLB information and exports it to a file
// Parameters:
//   - loadBalancerName: The name of the load balancer to query
//   - outputFile: The output file path to save the results
// Returns:
//   - string: The command output
//   - error: Any error that occurred during execution
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Validate input parameters
	if loadBalancerName == "" {
		return "", fmt.Errorf("loadBalancerName cannot be empty")
	}
	if outputFile == "" {
		return "", fmt.Errorf("outputFile cannot be empty")
	}

	// Create the aliyun command with parameters
	aliyunCmd := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)

	// Create the jq command to filter the output
	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	// Create or truncate the output file
	outputFileHandle, err := os.Create(outputFile)
	if err != nil {
		return "", fmt.Errorf("failed to create output file: %w", err)
	}
	defer outputFileHandle.Close()

	// Set up the pipe: aliyun | jq > output.json
	jqCmd.Stdin, err = aliyunCmd.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create pipe from aliyun to jq: %w", err)
	}

	// Redirect jq output to the file
	jqCmd.Stdout = outputFileHandle
	jqCmd.Stderr = os.Stderr

	// Start both commands
	if err := aliyunCmd.Start(); err != nil {
		return "", fmt.Errorf("failed to start aliyun command: %w", err)
	}

	if err := jqCmd.Start(); err != nil {
		return "", fmt.Errorf("failed to start jq command: %w", err)
	}

	// Wait for both commands to complete
	if err := aliyunCmd.Wait(); err != nil {
		return "", fmt.Errorf("aliyun command failed: %w", err)
	}

	if err := jqCmd.Wait(); err != nil {
		return "", fmt.Errorf("jq command failed: %w", err)
	}

	return fmt.Sprintf("Successfully exported SLB information to %s", outputFile), nil
}

func main() {
	// Example usage
	loadBalancerName := "my-slb"
	outputFile := "output.json"

	result, err := QuerySLBAndExport(loadBalancerName, outputFile)
	if err != nil {
		fmt.Fprintf(os.Stderr, "Error: %v\n", err)
		os.Exit(1)
	}

	fmt.Println(result)
}

