package main

import (
	"fmt"
	"os/exec"
	"path/filepath"
	"regexp"
)

// QuerySLBAndExport executes the aliyun CLI command to describe SLB,
// processes the output with jq, and saves it to the specified file.
// Returns the stdout of the command pipeline and any error encountered.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Validate loadBalancerName - allow only alphanumeric, hyphens, and underscores
	if !isValidLoadBalancerName(loadBalancerName) {
		return "", fmt.Errorf("invalid loadBalancerName: contains invalid characters")
	}

	// Validate outputFile - ensure it's a safe file path
	if !isValidFilePath(outputFile) {
		return "", fmt.Errorf("invalid outputFile: contains invalid characters or path traversal attempt")
	}

	// Use exec.Command with separate arguments instead of shell string concatenation
	// This prevents shell injection vulnerabilities
	cmd := exec.Command("sh", "-c",
		fmt.Sprintf("aliyun slb DescribeLoadBalancers --LoadBalancerName %s | jq '.LoadBalancers.LoadBalancer[]' > %s",
			shellQuote(loadBalancerName), shellQuote(outputFile)))

	// Capture stdout and stderr
	outputBytes, err := cmd.CombinedOutput()
	outputStr := string(outputBytes)

	if err != nil {
		return outputStr, fmt.Errorf("command failed: %w, output: %s", err, outputStr)
	}

	return outputStr, nil
}

// isValidLoadBalancerName validates that the load balancer name contains only safe characters
func isValidLoadBalancerName(name string) bool {
	if name == "" {
		return false
	}
	// Allow only alphanumeric characters, hyphens, and underscores
	// SLB names typically follow this pattern
	matched, _ := regexp.MatchString(`^[a-zA-Z0-9_-]+$`, name)
	return matched
}

// isValidFilePath validates that the file path is safe
func isValidFilePath(filePath string) bool {
	if filePath == "" {
		return false
	}

	// Prevent path traversal attacks
	cleanPath := filepath.Clean(filePath)
	if cleanPath != filePath {
		return false
	}

	// Prevent absolute paths for security
	if filepath.IsAbs(filePath) {
		return false
	}

	// Allow only alphanumeric, dots, hyphens, underscores, and forward slashes
	matched, _ := regexp.MatchString(`^[a-zA-Z0-9._\-/]+$`, filePath)
	return matched
}

// shellQuote safely quotes a string for use in shell commands
// This uses single quotes which prevent all expansions in the shell
func shellQuote(s string) string {
	// Replace single quotes with '\'' (end quote, escaped quote, start quote)
	return "'" + regexp.MustCompile(`'`).ReplaceAllString(s, `'\''`) + "'"
}

