package main

import (
	"fmt"
	"os"
	"os/exec"
	"regexp"
)

// QuerySLBAndExport executes the aliyun CLI command to describe SLB,
// processes the output with jq, and saves it to the specified file.
// Returns the output of the command pipeline and any error encountered.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Validate loadBalancerName - allow alphanumeric, hyphens, and underscores
	if !isValidLoadBalancerName(loadBalancerName) {
		return "", fmt.Errorf("invalid load balancer name: contains invalid characters")
	}

	// Validate outputFile - allow alphanumeric, hyphens, underscores, dots, and forward slashes
	if !isValidFilePath(outputFile) {
		return "", fmt.Errorf("invalid output file path: contains invalid characters")
	}

	// Execute aliyun command with proper argument passing (no shell injection)
	aliyunCmd := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)

	// Execute jq command to process the output
	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	// Create a pipe between aliyun and jq
	pipe, err := aliyunCmd.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create pipe: %w", err)
	}

	jqCmd.Stdin = pipe

	// Start aliyun command first
	if err := aliyunCmd.Start(); err != nil {
		return "", fmt.Errorf("failed to start aliyun command: %w", err)
	}

	// Capture jq output
	outputBytes, err := jqCmd.Output()
	if err != nil {
		aliyunCmd.Wait()
		return "", fmt.Errorf("jq command failed: %w", err)
	}

	// Wait for aliyun command to finish
	if err := aliyunCmd.Wait(); err != nil {
		return "", fmt.Errorf("aliyun command failed: %w", err)
	}

	// Write output to file safely
	if err := os.WriteFile(outputFile, outputBytes, 0644); err != nil {
		return "", fmt.Errorf("failed to write output file: %w", err)
	}

	return string(outputBytes), nil
}

// isValidLoadBalancerName validates the load balancer name using whitelist approach
func isValidLoadBalancerName(name string) bool {
	if name == "" || len(name) > 255 {
		return false
	}
	// Allow alphanumeric, hyphens, and underscores
	matched, _ := regexp.MatchString(`^[a-zA-Z0-9_-]+$`, name)
	return matched
}

// isValidFilePath validates the output file path using whitelist approach
func isValidFilePath(path string) bool {
	if path == "" || len(path) > 4096 {
		return false
	}
	// Allow alphanumeric, hyphens, underscores, dots, forward slashes, and colons (for absolute paths)
	matched, _ := regexp.MatchString(`^[a-zA-Z0-9_./:-]+$`, path)
	return matched
}

func main() {
	// Example usage
	result, err := QuerySLBAndExport("my-slb", "output.json")
	if err != nil {
		fmt.Printf("Error: %v\n", err)
		return
	}
	fmt.Printf("Success: %s\n", result)
}

