// QuerySLBAndExport queries SLB information and exports it to a file
// Parameters:
//   - loadBalancerName: The name of the load balancer to query
//   - outputFile: The path to the output file where results will be saved
// Returns:
//   - string: The command execution result
//   - error: Any error that occurred during execution
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Build the aliyun command with jq piping
	// Command: aliyun slb DescribeLoadBalancers --LoadBalancerName NAME | jq '.LoadBalancers.LoadBalancer[]' > output.json

	// Create the aliyun command
	aliyunCmd := exec.Command(
		"aliyun",
		"slb",
		"DescribeLoadBalancers",
		"--LoadBalancerName",
		loadBalancerName,
	)

	// Create the jq command to filter the output
	jqCmd := exec.Command(
		"jq",
		".LoadBalancers.LoadBalancer[]",
	)

	// Set up the pipe: aliyun output -> jq input
	pipe, err := aliyunCmd.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create pipe from aliyun command: %w", err)
	}

	jqCmd.Stdin = pipe

	// Create or truncate the output file
	outFile, err := os.Create(outputFile)
	if err != nil {
		return "", fmt.Errorf("failed to create output file %s: %w", outputFile, err)
	}
	defer outFile.Close()

	// Set jq output to the file
	jqCmd.Stdout = outFile
	jqCmd.Stderr = os.Stderr

	// Start both commands
	if err := aliyunCmd.Start(); err != nil {
		return "", fmt.Errorf("failed to start aliyun command: %w", err)
	}

	if err := jqCmd.Start(); err != nil {
		return "", fmt.Errorf("failed to start jq command: %w", err)
	}

	// Wait for both commands to complete
	if err := aliyunCmd.Wait(); err != nil {
		return "", fmt.Errorf("aliyun command failed: %w", err)
	}

	if err := jqCmd.Wait(); err != nil {
		return "", fmt.Errorf("jq command failed: %w", err)
	}

	// Read the output file to return as result
	content, err := os.ReadFile(outputFile)
	if err != nil {
		return "", fmt.Errorf("failed to read output file %s: %w", outputFile, err)
	}

	result := fmt.Sprintf("Successfully exported SLB information for '%s' to '%s'\n%s", 
		loadBalancerName, outputFile, strings.TrimSpace(string(content)))

	return result, nil
}

func main() {
	// Example usage
	loadBalancerName := "my-load-balancer"
	outputFile := "output.json"

	// Check if command line arguments are provided
	if len(os.Args) > 1 {
		loadBalancerName = os.Args[1]
	}
	if len(os.Args) > 2 {
		outputFile = os.Args[2]
	}

	fmt.Printf("Querying SLB: %s\n", loadBalancerName)
	fmt.Printf("Output file: %s\n", outputFile)

	result, err := QuerySLBAndExport(loadBalancerName, outputFile)
	if err != nil {
		fmt.Fprintf(os.Stderr, "Error: %v\n", err)
		os.Exit(1)
	}

	fmt.Println(result)
}

