	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	// Create a pipe to connect aliyun's stdout to jq's stdin
	pipe, err := aliyunCmd.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create pipe: %w", err)
	}

	// Connect jq's stdin to the pipe
	jqCmd.Stdin = pipe

	// Open output file for writing
	outputFileHandle, err := os.Create(outputFile)
	if err != nil {
