// QuerySLBAndExport queries SLB information and exports it to a file
// It runs: aliyun slb DescribeLoadBalancers --LoadBalancerName NAME | jq '.LoadBalancers.LoadBalancer[]' > output.json
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Validate input parameters
	if loadBalancerName == "" {
		return "", fmt.Errorf("loadBalancerName cannot be empty")
	}
	if outputFile == "" {
		return "", fmt.Errorf("outputFile cannot be empty")
	}

	// Create the aliyun command
	aliyunCmd := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)

	// Create the jq command
	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	// Connect aliyun output to jq input
	var err error
	jqCmd.Stdin, err = aliyunCmd.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create pipe between aliyun and jq: %w", err)
	}

	// Open output file for writing
	outputFileHandle, err := os.Create(outputFile)
	if err != nil {
		return "", fmt.Errorf("failed to create output file %s: %w", outputFile, err)
	}
	defer outputFileHandle.Close()

	// Connect jq output to file
	jqCmd.Stdout = outputFileHandle
	jqCmd.Stderr = os.Stderr

	// Start aliyun command
	err = aliyunCmd.Start()
	if err != nil {
		return "", fmt.Errorf("failed to start aliyun command: %w", err)
	}

	// Start jq command
	err = jqCmd.Start()
	if err != nil {
		return "", fmt.Errorf("failed to start jq command: %w", err)
	}

	// Wait for aliyun command to complete
	err = aliyunCmd.Wait()
	if err != nil {
		return "", fmt.Errorf("aliyun command failed: %w", err)
	}

	// Wait for jq command to complete
	err = jqCmd.Wait()
	if err != nil {
		return "", fmt.Errorf("jq command failed: %w", err)
	}

	successMsg := fmt.Sprintf("Successfully queried SLB '%s' and exported to '%s'", loadBalancerName, outputFile)
	return successMsg, nil
}

