// isValidLoadBalancerName validates the load balancer name
// Allows only alphanumeric characters, hyphens, and underscores
func isValidLoadBalancerName(name string) bool {
	if name == "" {
		return false
	}
	for _, char := range name {
		if !((char >= 'a' && char <= 'z') ||
			(char >= 'A' && char <= 'Z') ||
			(char >= '0' && char <= '9') ||
			char == '-' || char == '_') {
			return false
		}
	}
	return true
}

// isValidOutputFilePath validates the output file path
// Prevents directory traversal and ensures the path is within acceptable bounds
func isValidOutputFilePath(filePath string) error {
	if filePath == "" {
		return fmt.Errorf("output file path cannot be empty")
	}

	// Get the absolute path
	absPath, err := filepath.Abs(filePath)
	if err != nil {
		return fmt.Errorf("invalid file path: %w", err)
	}

	// Check for directory traversal attempts
	if strings.Contains(filePath, "..") {
		return fmt.Errorf("directory traversal not allowed")
	}

	// Ensure the file is not in sensitive directories
	dir := filepath.Dir(absPath)
	if dir == "/" || dir == "/etc" || dir == "/sys" || dir == "/proc" {
		return fmt.Errorf("cannot write to system directories")
	}

	return nil
}

// writeOutputFile safely writes the output to a file
func writeOutputFile(filePath string, data []byte) error {
	// Create the file with restricted permissions (0644)
	file, err := os.OpenFile(filePath, os.O_CREATE|os.O_WRONLY|os.O_TRUNC, 0644)
	if err != nil {
		return err
	}
	defer file.Close()

	_, err = file.Write(data)
	return err
}

